import { useEffect, useMemo, useState } from 'react';
import './App.css';

const STORAGE_KEY = 'my-life-kanban-v1';
const TOMORROW_SEED_KEY = 'my-life-tomorrow-seeded-v1';

const COLUMNS = [
  { id: 'todo', title: 'To Do' },
  { id: 'doing', title: 'In Progress' },
  { id: 'review', title: 'Review' },
  { id: 'done', title: 'Done' },
];

const defaultTasks = [
  {
    id: crypto.randomUUID(),
    title: 'Define weekly top priorities',
    notes: 'Set 3 outcomes for the week.',
    owner: 'Both',
    status: 'todo',
    createdAt: Date.now(),
  },
];

const tomorrowSuggestedTasks = [
  {
    title: 'Review weekly options swing watchlist',
    notes:
      'Scan event-driven setups, earnings/news catalysts, and shortlist 3 trades for this week.',
    owner: 'TheAIos',
  },
  {
    title: 'Draft Wellness Initiative weekly action plan',
    notes:
      'Create 3 concrete actions: community outreach, safe-space logistics, and one collaboration idea.',
    owner: 'TheAIos',
  },
  {
    title: 'Solar system progress check',
    notes:
      'List open steps needed to complete connection of batteries/panels and flag blockers.',
    owner: 'TheAIos',
  },
  {
    title: '3D printing project queue',
    notes:
      'Prepare a prioritized list of useful prints for home + Megan veterinary use + kid projects.',
    owner: 'Both',
  },
  {
    title: 'EV go-kart build next milestone',
    notes:
      'Define next build milestone with parts list, safety checks, and one weekend task.',
    owner: 'Both',
  },
  {
    title: 'Family schedule snapshot',
    notes:
      'Create a quick weekly rhythm plan for Joseph, Enok, Farrah, and household commitments.',
    owner: 'TheAIos',
  },
  {
    title: 'OpenClaw skill roadmap shortlist',
    notes:
      'Identify the next specific OpenClaw skills/tools to add safely (with malware/safety review).',
    owner: 'TheAIos',
  },
  {
    title: 'Rule: only start tasks after move to In Progress',
    notes:
      'Execution gate agreed: items in To Do are planning only; work starts only after manual move to In Progress.',
    owner: 'Both',
  },
];

const makeTask = ({ title, notes, owner, status = 'todo' }) => ({
  id: crypto.randomUUID(),
  title,
  notes,
  owner,
  status,
  createdAt: Date.now(),
});

function App() {
  const [tasks, setTasks] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (!saved) return defaultTasks;
    try {
      return JSON.parse(saved);
    } catch {
      return defaultTasks;
    }
  });

  const [title, setTitle] = useState('');
  const [notes, setNotes] = useState('');
  const [owner, setOwner] = useState('Both');
  const [editingTaskId, setEditingTaskId] = useState(null);
  const [editTitle, setEditTitle] = useState('');
  const [editNotes, setEditNotes] = useState('');
  const [editOwner, setEditOwner] = useState('Both');

  useEffect(() => {
    const seeded = localStorage.getItem(TOMORROW_SEED_KEY);
    if (seeded) return;

    setTasks((prev) => {
      const seededTasks = tomorrowSuggestedTasks.map((task) => makeTask(task));
      return [...seededTasks, ...prev];
    });
    localStorage.setItem(TOMORROW_SEED_KEY, 'true');
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
  }, [tasks]);

  const counts = useMemo(() => {
    return COLUMNS.reduce((acc, col) => {
      acc[col.id] = tasks.filter((t) => t.status === col.id).length;
      return acc;
    }, {});
  }, [tasks]);

  const addTask = (e) => {
    e.preventDefault();
    if (!title.trim()) return;

    const newTask = {
      id: crypto.randomUUID(),
      title: title.trim(),
      notes: notes.trim(),
      owner,
      status: 'todo',
      createdAt: Date.now(),
    };

    setTasks((prev) => [newTask, ...prev]);
    setTitle('');
    setNotes('');
    setOwner('Both');
  };

  const moveTask = (taskId, newStatus) => {
    setTasks((prev) =>
      prev.map((task) =>
        task.id === taskId ? { ...task, status: newStatus } : task
      )
    );
  };

  const removeTask = (taskId) => {
    setTasks((prev) => prev.filter((task) => task.id !== taskId));
    if (editingTaskId === taskId) setEditingTaskId(null);
  };

  const startEditing = (task) => {
    setEditingTaskId(task.id);
    setEditTitle(task.title);
    setEditNotes(task.notes || '');
    setEditOwner(task.owner || 'Both');
  };

  const cancelEditing = () => {
    setEditingTaskId(null);
    setEditTitle('');
    setEditNotes('');
    setEditOwner('Both');
  };

  const saveEdit = (taskId) => {
    if (!editTitle.trim()) return;
    setTasks((prev) =>
      prev.map((task) =>
        task.id === taskId
          ? {
              ...task,
              title: editTitle.trim(),
              notes: editNotes.trim(),
              owner: editOwner,
            }
          : task
      )
    );
    cancelEditing();
  };

  return (
    <div className="app-shell">
      <header className="topbar">
        <h1>My Life Board</h1>
        <p>Elegant, shared Kanban for Joseph + TheAIos</p>
      </header>

      <section className="composer-card">
        <form onSubmit={addTask} className="composer-form">
          <input
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Add a task..."
            aria-label="Task title"
          />
          <input
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
            placeholder="Optional details"
            aria-label="Task details"
          />
          <select value={owner} onChange={(e) => setOwner(e.target.value)}>
            <option>Both</option>
            <option>Joseph</option>
            <option>TheAIos</option>
          </select>
          <button type="submit">Add</button>
        </form>
      </section>

      <main className="board">
        {COLUMNS.map((column) => (
          <section
            key={column.id}
            className="column"
            onDragOver={(e) => e.preventDefault()}
            onDrop={(e) => {
              const taskId = e.dataTransfer.getData('text/plain');
              if (taskId) moveTask(taskId, column.id);
            }}
          >
            <div className="column-head">
              <h2>{column.title}</h2>
              <span>{counts[column.id] || 0}</span>
            </div>

            <div className="column-body">
              {tasks
                .filter((task) => task.status === column.id)
                .map((task) => {
                  const isEditing = editingTaskId === task.id;

                  return (
                    <article
                      key={task.id}
                      className="task"
                      draggable={!isEditing}
                      onDragStart={(e) =>
                        e.dataTransfer.setData('text/plain', task.id)
                      }
                    >
                      {isEditing ? (
                        <div className="task-edit">
                          <input
                            value={editTitle}
                            onChange={(e) => setEditTitle(e.target.value)}
                            placeholder="Task title"
                          />
                          <input
                            value={editNotes}
                            onChange={(e) => setEditNotes(e.target.value)}
                            placeholder="Task details"
                          />
                          <select
                            value={editOwner}
                            onChange={(e) => setEditOwner(e.target.value)}
                          >
                            <option>Both</option>
                            <option>Joseph</option>
                            <option>TheAIos</option>
                          </select>
                          <div className="task-actions">
                            <button
                              className="action-btn save"
                              onClick={() => saveEdit(task.id)}
                            >
                              Save
                            </button>
                            <button
                              className="action-btn"
                              onClick={cancelEditing}
                            >
                              Cancel
                            </button>
                          </div>
                        </div>
                      ) : (
                        <>
                          <div className="task-title">{task.title}</div>
                          {task.notes ? <p>{task.notes}</p> : null}
                          <div className="task-footer">
                            <span className="pill">{task.owner}</span>
                            <div className="task-actions">
                              <button
                                className="action-btn"
                                onClick={() => startEditing(task)}
                              >
                                Edit
                              </button>
                              <button
                                className="action-btn delete"
                                onClick={() => removeTask(task.id)}
                              >
                                Delete
                              </button>
                            </div>
                          </div>
                        </>
                      )}
                    </article>
                  );
                })}
            </div>
          </section>
        ))}
      </main>
    </div>
  );
}

export default App;
